    private function osLinuxTerms(): array
    {
        return ['os-linux' => [
            ['name'=>'ファイルシステム（ext4/xfs）','definition'=>'ディスク上のデータをファイル・ディレクトリとして管理する構造。LinuxはExt4がデフォルト、XFSは大容量向け。NTFS(Windows)・APFS(Mac)など。','example'=>'sudo mkfs.ext4 /dev/sdb1 で新しいディスクパーティションをExt4でフォーマットしてマウントして使う。','difficulty'=>3,'quiz'=>['question'=>'Linuxで最も広く使われるファイルシステムはどれか？','explanation'=>'Ext4（Fourth Extended Filesystem）は信頼性とパフォーマンスのバランスが良く、多くのLinuxディストリビューションのデフォルトとして採用されている。','choices'=>[['body'=>'NTFS','is_correct'=>false],['body'=>'Ext4','is_correct'=>true],['body'=>'FAT32','is_correct'=>false],['body'=>'APFS','is_correct'=>false]]]],
            ['name'=>'マウント（mount）','definition'=>'ストレージデバイス・パーティション・ネットワーク共有をファイルシステムの特定ディレクトリに接続する操作。','example'=>'sudo mount /dev/sdb1 /mnt/data でUSBメモリを/mnt/dataにマウントし、そこでファイルにアクセスできるようになる。','difficulty'=>2,'quiz'=>['question'=>'LinuxでUSBメモリなどを/mnt/usbにマウントするコマンドはどれか？','explanation'=>'mountコマンドでデバイスファイル（/dev/sdb1等）をディレクトリに関連付ける。umountでアンマウント（取り外し）する。','choices'=>[['body'=>'sudo attach /dev/sdb1 /mnt/usb','is_correct'=>false],['body'=>'sudo mount /dev/sdb1 /mnt/usb','is_correct'=>true],['body'=>'sudo connect /dev/sdb1 /mnt/usb','is_correct'=>false],['body'=>'sudo link /dev/sdb1 /mnt/usb','is_correct'=>false]]]],
            ['name'=>'LVM（Logical Volume Manager）','definition'=>'物理ボリューム（PV）→ボリュームグループ（VG）→論理ボリューム（LV）の階層で柔軟なディスク管理を実現する技術。ディスク追加・サイズ変更が容易。','example'=>'LVMでルートパーティションが足りなくなったとき、新しいディスクをVGに追加してLVを拡張することで無停止でディスクを増やせる。','difficulty'=>4,'quiz'=>['question'=>'LVMを使う主なメリットはどれか？','explanation'=>'LVMにより物理ディスクの境界を超えた論理ボリュームを作成でき、動的なサイズ変更・スナップショット・複数ディスクの統合が容易になる。','choices'=>[['body'=>'ディスクの読み書き速度が向上する','is_correct'=>false],['body'=>'物理ディスクに依存せず柔軟にボリュームサイズを変更できる','is_correct'=>true],['body'=>'自動的にRAIDを構成する','is_correct'=>false],['body'=>'ファイルシステムの種類を変更できる','is_correct'=>false]]]],
            ['name'=>'RAID（Redundant Array of Inexpensive Disks）','definition'=>'複数のディスクを組み合わせて冗長性やパフォーマンスを向上させる技術。RAID0（ストライピング）・RAID1（ミラーリング）・RAID5・RAID6など。','example'=>'RAID1でディスク2台を同じデータでミラーリングし、1台故障しても残りから復旧できる可用性を確保する。','difficulty'=>3,'quiz'=>['question'=>'RAID1（ミラーリング）の特徴はどれか？','explanation'=>'RAID1は同一データを2台以上のディスクに書き込む。1台故障しても他のディスクからデータを復旧できる高可用性を提供するがストレージ効率は50%。','choices'=>[['body'=>'データを分散して高速読み書きする','is_correct'=>false],['body'=>'同一データを複数ディスクにコピーして耐障害性を確保する','is_correct'=>true],['body'=>'パリティ情報で1台故障から復旧できる','is_correct'=>false],['body'=>'データを圧縮して保存する','is_correct'=>false]]]],
            ['name'=>'awk','definition'=>'パターンマッチングとフィールド処理に特化したテキスト処理プログラミング言語/コマンド。CSVや空白区切りデータの加工に最適。','example'=>'ps aux | awk \'{print $1, $2, $11}\' でプロセス一覧からユーザー名・PID・コマンドを抽出して表示する。','difficulty'=>3,'quiz'=>['question'=>'awkのフィールド区切り変数はどれか？','explanation'=>'awkではデフォルトで空白・タブがフィールド区切りで、$1が1番目のフィールド、$2が2番目...、$0が行全体を表す。FSで区切り文字を変更できる。','choices'=>[['body'=>'$col と $row','is_correct'=>false],['body'=>'$1, $2...（番号で各フィールド、$0は行全体）','is_correct'=>true],['body'=>'[1], [2]','is_correct'=>false],['body'=>'%1, %2','is_correct'=>false]]]],
            ['name'=>'sed（Stream Editor）','definition'=>'テキストの置換・削除・挿入・抽出をストリームで行うコマンド。スクリプトで大量のファイルを一括変換するのに使われる。','example'=>'sed -i "s/localhost/production.example.com/g" config.txt でconfig.txt内のlocalhostを全て置換する。','difficulty'=>3,'quiz'=>['question'=>'sed \'s/foo/bar/g\' の意味はどれか？','explanation'=>'sはsubstitute（置換）コマンド、/foo/bar/はfooをbarに置換するパターン、gフラグは行内の全マッチを置換（デフォルトは最初の1つのみ）。','choices'=>[['body'=>'fooを削除してbarを表示する','is_correct'=>false],['body'=>'行内のfooを全てbarに置換する','is_correct'=>true],['body'=>'fooとbarの行を入れ替える','is_correct'=>false],['body'=>'fooを含む行を削除する','is_correct'=>false]]]],
            ['name'=>'find','definition'=>'ファイル・ディレクトリを名前・種類・サイズ・更新日時などの条件で検索するコマンド。-execオプションでマッチしたファイルに処理を適用できる。','example'=>'find /var/log -name "*.log" -mtime +30 -exec rm {} \\; で30日以上前の.logファイルを自動削除する。','difficulty'=>2,'quiz'=>['question'=>'find . -name "*.py" -type f コマンドが検索するものはどれか？','explanation'=>'-type fはファイル（directoryでない）に限定し、-name "*.py"はPythonファイルのみを対象にする。合わせてカレントディレクトリ以下のPythonファイルを検索。','choices'=>[['body'=>'pyという名前のディレクトリ','is_correct'=>false],['body'=>'カレントディレクトリ以下の.pyファイル','is_correct'=>true],['body'=>'Pythonがインストールされているパス','is_correct'=>false],['body'=>'.pyで終わるシンボリックリンク','is_correct'=>false]]]],
            ['name'=>'xargs','definition'=>'標準入力や別コマンドの出力を引数として別コマンドに渡すコマンド。パイプと組み合わせて大量のファイルを一括処理するのに使われる。','example'=>'find . -name "*.tmp" | xargs rm でfindで見つかった全tmpファイルをrmコマンドで削除する。','difficulty'=>3,'quiz'=>['question'=>'xargsを使う主な理由はどれか？','explanation'=>'パイプは出力を次コマンドの「標準入力」に渡すが、rmなど引数として受け取る必要があるコマンドにはxargsを使い標準入力を「引数」として渡す。','choices'=>[['body'=>'コマンドを並列実行するため','is_correct'=>false],['body'=>'標準入力を別コマンドの引数として渡すため','is_correct'=>true],['body'=>'テキストを置換するため','is_correct'=>false],['body'=>'ファイルを圧縮するため','is_correct'=>false]]]],
            ['name'=>'tar（アーカイブ）','definition'=>'複数ファイルを1つのアーカイブファイルにまとめるコマンド。gzip/bzip2/xzと組み合わせて圧縮もできる。','example'=>'tar -czf backup.tar.gz /var/www で/var/wwwをgzip圧縮したアーカイブを作成。tar -xzf backup.tar.gz で解凍。','difficulty'=>1,'quiz'=>['question'=>'tar -xzf archive.tar.gz の各オプションの意味はどれか？','explanation'=>'x=extract（解凍）、z=gzip圧縮/解凍を経由、f=ファイル名を指定。合わせてgzip圧縮されたtarアーカイブを解凍するオプション。','choices'=>[['body'=>'x=削除 z=zip圧縮 f=強制実行','is_correct'=>false],['body'=>'x=解凍 z=gzip処理 f=ファイル指定','is_correct'=>true],['body'=>'x=実行 z=サイズ表示 f=ファイル検索','is_correct'=>false],['body'=>'x=暗号化 z=圧縮率 f=フォルダ指定','is_correct'=>false]]]],
            ['name'=>'rsync','definition'=>'差分のみを転送する効率的なファイル同期・バックアップコマンド。ローカル/リモート間の同期とSSHを使った安全な転送が可能。','example'=>'rsync -avz /local/data/ user@remote:/backup/data/ でローカルファイルをリモートサーバーに差分同期する。','difficulty'=>2,'quiz'=>['question'=>'rsyncがscpより優れている主な点はどれか？','explanation'=>'rsyncは差分のみを転送するため2回目以降のバックアップが高速。scpは毎回ファイル全体を転送するため大量ファイルの同期に非効率。','choices'=>[['body'=>'暗号化が強力','is_correct'=>false],['body'=>'差分のみ転送して2回目以降のバックアップが高速','is_correct'=>true],['body'=>'GUIで操作できる','is_correct'=>false],['body'=>'FTPより使いやすい','is_correct'=>false]]]],
            ['name'=>'ssh-keygen（鍵管理）','definition'=>'SSH接続で使う公開鍵・秘密鍵ペアを生成するコマンド。パスワード認証より安全なSSH公開鍵認証を実現する。','example'=>'ssh-keygen -t ed25519 -C "mail@example.com" で鍵ペアを生成し、公開鍵（id_ed25519.pub）をサーバーの~/.ssh/authorized_keysに登録する。','difficulty'=>2,'quiz'=>['question'=>'SSH公開鍵認証でサーバーに登録するのはどちらの鍵か？','explanation'=>'公開鍵（id_rsa.pub, id_ed25519.pub）をサーバーのauthorized_keysに登録する。秘密鍵はクライアントに保管し絶対にサーバーに送らない。','choices'=>[['body'=>'秘密鍵（id_rsa）','is_correct'=>false],['body'=>'公開鍵（id_rsa.pub）','is_correct'=>true],['body'=>'両方の鍵','is_correct'=>false],['body'=>'パスフレーズ','is_correct'=>false]]]],
            ['name'=>'ネットワーク設定（ipコマンド）','definition'=>'Linuxネットワークの設定・確認を行うコマンド。旧来のifconfigに代わるiproute2のipコマンドが現在の標準。','example'=>'ip addr show でネットワークインターフェースとIPアドレス確認。ip route show でルーティングテーブル表示。','difficulty'=>2,'quiz'=>['question'=>'LinuxでIPアドレスを確認する現代的なコマンドはどれか？','explanation'=>'現代のLinuxではipコマンド（iproute2パッケージ）が標準。ip addr はifconfigの代替、ip route はnetstatのroute機能の代替。','choices'=>[['body'=>'ipconfig','is_correct'=>false],['body'=>'ip addr show','is_correct'=>true],['body'=>'netcfg','is_correct'=>false],['body'=>'net show addr','is_correct'=>false]]]],
            ['name'=>'netstat / ss','definition'=>'ネットワーク接続・ルーティングテーブル・インターフェース統計・リスニングポートを表示するコマンド。ssはnetstatの高速版。','example'=>'ss -tulpn で現在リスニング中の全TCP/UDPポートとそれを使うプロセスを表示する。','difficulty'=>2,'quiz'=>['question'=>'ss -tulpn で確認できる情報はどれか？','explanation'=>'-t=TCP、-u=UDP、-l=LISTENのみ、-p=プロセス名、-n=数値表示。組み合わせでリスニング中のポートとプロセスを表示できる。','choices'=>[['body'=>'ディスク使用量','is_correct'=>false],['body'=>'リスニング中のTCP/UDPポートとプロセス名','is_correct'=>true],['body'=>'CPUの使用率','is_correct'=>false],['body'=>'実行中のDockerコンテナ一覧','is_correct'=>false]]]],
            ['name'=>'lsof（List Open Files）','definition'=>'システム上のプロセスが開いているファイル・ポート・ソケットを一覧表示するコマンド。特定ポートを使うプロセスの特定などに使われる。','example'=>'lsof -i :8080 でポート8080を使用しているプロセスを確認。lsof -u username でユーザーが開いているファイルを一覧表示。','difficulty'=>3,'quiz'=>['question'=>'ポート80を使用しているプロセスを確認するコマンドはどれか？','explanation'=>'lsof -i :80 でポート80を使用しているプロセスのPID・プロセス名・接続状態を表示する。ssやnetstatでも同様の確認が可能。','choices'=>[['body'=>'ps aux | grep 80','is_correct'=>false],['body'=>'lsof -i :80','is_correct'=>true],['body'=>'find / -name 80','is_correct'=>false],['body'=>'cat /proc/80','is_correct'=>false]]]],
            ['name'=>'ファイルディスクリプタ','definition'=>'Linuxでファイル・ソケット・パイプなどのI/Oリソースを表す整数値。0=標準入力、1=標準出力、2=標準エラー出力がデフォルト。','example'=>'コマンドを実行すると3, 4, 5...のFDが割り当てられる。cat /proc/PID/fd でプロセスが開いているFDを確認できる。','difficulty'=>3,'quiz'=>['question'=>'LinuxでFD 2（ファイルディスクリプタ2）が表すものはどれか？','explanation'=>'fd0=標準入力（stdin）、fd1=標準出力（stdout）、fd2=標準エラー出力（stderr）がデフォルトで割り当てられる。','choices'=>[['body'=>'標準入力（stdin）','is_correct'=>false],['body'=>'標準エラー出力（stderr）','is_correct'=>true],['body'=>'標準出力（stdout）','is_correct'=>false],['body'=>'最初に開いたファイル','is_correct'=>false]]]],
            ['name'=>'ulimit','definition'=>'プロセスが使用できるリソース（開けるファイル数・メモリ・プロセス数・ファイルサイズ）の上限を設定するコマンド。','example'=>'ulimit -n 65536 でセッションのopenfile数上限を65536に増やす。高接続数のNginxやDB設定で必要になる。','difficulty'=>3,'quiz'=>['question'=>'ulimit -n が制御するリソースはどれか？','explanation'=>'-n（files）は1プロセスが同時に開けるファイルディスクリプタの最大数を制御する。Webサーバーの同時接続数に影響する重要パラメータ。','choices'=>[['body'=>'最大プロセス数','is_correct'=>false],['body'=>'同時に開けるファイルディスクリプタの最大数','is_correct'=>true],['body'=>'最大メモリ使用量','is_correct'=>false],['body'=>'CPUコア数の割り当て','is_correct'=>false]]]],
            ['name'=>'ジョブ制御（jobs, fg, bg）','definition'=>'シェルでコマンドをバックグラウンドで実行したり（&）、フォアグラウンドとバックグラウンドを切り替えるシェルの機能。','example'=>'command & でバックグラウンド実行、Ctrl+Zで一時停止、bg %1 でバックグラウンド再開、fg %1 でフォアグラウンドに戻す。','difficulty'=>2,'quiz'=>['question'=>'コマンドをバックグラウンドで実行する方法はどれか？','explanation'=>'コマンドの末尾に & を付けるとバックグラウンドで実行され、ターミナルがすぐ戻る。[1] 12345 のようにジョブ番号とPIDが表示される。','choices'=>[['body'=>'sudo command','is_correct'=>false],['body'=>'command &','is_correct'=>true],['body'=>'bg command','is_correct'=>false],['body'=>'nohup command','is_correct'=>false]]]],
            ['name'=>'alias（エイリアス）','definition'=>'長いコマンドや頻繁に使うコマンドに短い別名を定義する機能。~/.bashrcに記述して永続化する。','example'=>'alias ll="ls -la --color" と定義すると、以降 ll と入力するだけで ls -la --color が実行される。','difficulty'=>1,'quiz'=>['question'=>'aliasを永続化（ログイン後も有効）させるには何に記述するか？','explanation'=>'aliasをターミナルで設定しても、セッションが終わると消える。~/.bashrc（Bash）や~/.zshrc（Zsh）に記述してsource ~/.bashrcで読み込み直すと永続化される。','choices'=>[['body'=>'/etc/passwd','is_correct'=>false],['body'=>'~/.bashrc（または~/.zshrc）','is_correct'=>true],['body'=>'/proc/alias','is_correct'=>false],['body'=>'/bin/alias','is_correct'=>false]]]],
            ['name'=>'historyコマンド','definition'=>'過去に実行したコマンドの履歴を表示するコマンド。!番号で履歴の再実行、!!で直前のコマンド、Ctrl+Rで逆検索ができる。','example'=>'history | grep "docker" で過去に実行したdockerコマンドを絞り込み。!234 でhistory番号234のコマンドを再実行。','difficulty'=>1,'quiz'=>['question'=>'Ctrl+R の機能はどれか？','explanation'=>'Ctrl+Rはreverse-i-searchで、過去のコマンド履歴をインクリメンタルに逆検索する機能。文字を入力するたびに一致するコマンドが絞り込まれる。','choices'=>[['body'=>'コマンドを中断する','is_correct'=>false],['body'=>'コマンド履歴を逆検索する','is_correct'=>true],['body'=>'新しいターミナルを開く','is_correct'=>false],['body'=>'前のコマンドをキャンセルする','is_correct'=>false]]]],
            ['name'=>'ハードリンク','definition'=>'同一ファイルのinodeを指す別の名前（ディレクトリエントリ）。元ファイルを削除してもハードリンクが残ればデータは消えない。','example'=>'ln original.txt hardlink.txt でハードリンクを作成。ls -li で両ファイルが同じinode番号を持つことを確認できる。','difficulty'=>3,'quiz'=>['question'=>'ハードリンクの特性として正しいものはどれか？','explanation'=>'ハードリンクは同一inodeを共有するため、元のファイルを削除してもハードリンクが残ればデータは削除されない（inodeの参照カウントが0になるまで保持）。','choices'=>[['body'=>'シンボリックリンクと同じ仕組み','is_correct'=>false],['body'=>'元ファイル削除後もハードリンクでデータにアクセスできる','is_correct'=>true],['body'=>'異なるファイルシステムをまたいで作成できる','is_correct'=>false],['body'=>'ディレクトリにも作成できる（通常ユーザーでも）','is_correct'=>false]]]],
            ['name'=>'strace','definition'=>'プロセスが行うシステムコールとシグナルをリアルタイムに追跡するデバッグツール。障害調査・パフォーマンス分析に使われる。','example'=>'strace -p 1234 で実行中のプロセス(PID=1234)のシステムコールをリアルタイム表示し、どのファイルにアクセスしているか追跡する。','difficulty'=>4,'quiz'=>['question'=>'straceが主に使われる場面はどれか？','explanation'=>'straceはプロセスが実行するシステムコール（open・read・write・connect等）を逐一表示するため、アプリの動作不明時やパフォーマンス調査に有用。','choices'=>[['body'=>'ネットワークパケットを解析する','is_correct'=>false],['body'=>'プロセスのシステムコールを追跡してデバッグする','is_correct'=>true],['body'=>'ディスクのI/O速度を計測する','is_correct'=>false],['body'=>'CPUのキャッシュミスを計測する','is_correct'=>false]]]],
            ['name'=>'カーネルモジュール','definition'=>'実行中のLinuxカーネルに動的にロード・アンロードできるドライバー・機能の単位。lsmod・modprobe・rmmodで管理する。','example'=>'modprobe nf_conntrack でファイアウォール用カーネルモジュールをロード。lsmod でロード済みモジュール一覧を表示する。','difficulty'=>4,'quiz'=>['question'=>'Linuxカーネルモジュールを手動でロードするコマンドはどれか？','explanation'=>'modprobeは依存するモジュールも自動的にロードする推奨コマンド。insmodは単体ファイルを直接ロードするがdep解決なし。','choices'=>[['body'=>'apt install module-name','is_correct'=>false],['body'=>'modprobe module-name','is_correct'=>true],['body'=>'systemctl start module-name','is_correct'=>false],['body'=>'load kernel module-name','is_correct'=>false]]]],
            ['name'=>'プロセス間通信（IPC）','definition'=>'同一システム上の異なるプロセスがデータを交換する仕組み。パイプ・ソケット・共有メモリ・メッセージキュー・シグナル等がある。','example'=>'名前付きパイプ（FIFO）でWebサーバーとバックエンドプロセスを接続し、高速なIPC通信を実現する。','difficulty'=>4,'quiz'=>['question'=>'同一ホスト上のプロセス間通信で最速の手段はどれか？','explanation'=>'共有メモリはメモリをプロセス間で直接共有するためデータのコピーが不要で最速。ただし競合管理のためミューテックス等が必要。','choices'=>[['body'=>'TCPソケット','is_correct'=>false],['body'=>'共有メモリ（Shared Memory）','is_correct'=>true],['body'=>'名前付きパイプ','is_correct'=>false],['body'=>'シグナル','is_correct'=>false]]]],
